using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private readonly PriceCalculator _calculator = new();

    // --- CalculateTotal: inline data with [DataRow] ---

    [TestMethod]
    [DataRow(10.00, 1, 0.0, 10.00, DisplayName = "No tax")]
    [DataRow(10.00, 2, 0.1, 22.00, DisplayName = "10% tax, qty 2")]
    [DataRow(25.50, 4, 0.08, 110.16, DisplayName = "8% tax, qty 4")]
    [DataRow(0.00, 5, 0.2, 0.00, DisplayName = "Zero price")]
    [DataRow(99.99, 0, 0.15, 0.00, DisplayName = "Zero quantity")]
    [DataRow(10.00, 1, 1.0, 20.00, DisplayName = "100% tax")]
    public void CalculateTotal_WithValidInputs_ReturnsExpected(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    // --- CalculateTotal: validation errors with [DataRow] ---

    [TestMethod]
    [DataRow(10.00, -1, 0.1, "quantity", DisplayName = "Negative quantity")]
    [DataRow(-5.00, 2, 0.1, "unitPrice", DisplayName = "Negative price")]
    [DataRow(10.00, 1, -0.1, "taxRate", DisplayName = "Negative tax rate")]
    [DataRow(10.00, 1, 1.5, "taxRate", DisplayName = "Tax rate > 1")]
    public void CalculateTotal_WithInvalidInputs_ThrowsArgumentOutOfRange(
        double unitPrice, int quantity, double taxRate, string expectedParam)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));

        Assert.AreEqual(expectedParam, ex.ParamName);
    }

    // --- ApplyDiscount: [DynamicData] with ValueTuples ---

    [TestMethod]
    [DynamicData(nameof(DiscountTestData))]
    public void ApplyDiscount_WithValidInputs_ReturnsExpected(
        decimal price, decimal discountPercent, decimal expected)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);

        Assert.AreEqual(expected, result);
    }

    public static IEnumerable<(decimal price, decimal discountPercent, decimal expected)> DiscountTestData =>
    [
        (100m, 0m, 100m),
        (100m, 10m, 90m),
        (200m, 25m, 150m),
        (80m, 50m, 40m),
        (100m, 100m, 0m),
        (0m, 50m, 0m),
    ];

    [TestMethod]
    [DataRow(-1.0, DisplayName = "Discount below 0")]
    [DataRow(101.0, DisplayName = "Discount above 100")]
    public void ApplyDiscount_WithInvalidPercent_ThrowsArgumentOutOfRange(double discountPercent)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(100m, (decimal)discountPercent));
    }

    // --- FormatPrice ---

    [TestMethod]
    [DataRow(9.99, "$", "$9.99", DisplayName = "Default symbol")]
    [DataRow(1234.5, "€", "€1234.50", DisplayName = "Euro symbol")]
    [DataRow(0.0, "£", "£0.00", DisplayName = "Zero with pound")]
    public void FormatPrice_WithSymbol_ReturnsFormattedString(
        double price, string symbol, string expected)
    {
        var result = _calculator.FormatPrice((decimal)price, symbol);

        Assert.AreEqual(expected, result);
    }
}

